INSERT INTO rule (code, name, version, status, rule_type_id, canvas_data, drools_drl, remark, created_at, updated_at) VALUES ('SR_00002', '主动脉瓣生物瓣膜置换术', '1.0.0', 'DRAFT', @rule_type_id, '{"nodes": [{"id": "start_1", "type": "start", "position": {"x": 250, "y": 50}, "data": {"label": "开始"}}, {"id": "cond_2", "type": "condition", "position": {"x": 250, "y": 150}, "data": {"label": "检查结果值:LVEF", "conditionConfig": {"field": "lvefValue", "operator": "<", "value": "50", "valueSource": "ADAPTER", "dictAttr": "itemName"}}}, {"id": "cond_3", "type": "condition", "position": {"x": 250, "y": 250}, "data": {"label": "手术:主动脉瓣生物瓣膜置换术", "conditionConfig": {"field": "surgeryOrder", "operator": "contains", "value": "主动脉瓣生物瓣膜置换术", "valueSource": "ADAPTER", "dictAttr": "itemName"}}}, {"id": "result_4", "type": "result", "position": {"x": 250, "y": 350}, "data": {"label": "相对禁忌", "resultConfig": {"resultType": "QC_DEFECT", "resultValue": "相对禁忌", "content": "该患者彩超报告显示其LVEF值小于50%，代表严重心功能不全，即左心室收缩功能下降。主动脉瓣生物瓣膜置换术后，会改变患者的血流动力学状态，可能导致心脏需要重新适应新的血流模式。对于心功能不全的患者，心脏可能无法有效调节这些变化，导致进一步的心脏负担。故禁忌对严重心功能不全的患者行瓣膜置换术", "priority": 2}}}], "edges": [{"id": "e_start_1_cond_2", "source": "start_1", "target": "cond_2", "label": ""}, {"id": "e_cond_2_cond_3", "source": "cond_2", "target": "cond_3", "label": ""}, {"id": "e_cond_3_result_4", "source": "cond_3", "target": "result_4", "sourceHandle": "true", "label": "是"}]}', NULL, '相对禁忌', NOW(), NOW());
